MOD = 10**9 + 7

def modinv(a, p):
    return pow(a, p - 2, p)

def precompute_factorials_and_inverses(max_n, mod):
    fact = [1] * (2 * max_n + 1)
    inv_fact = [1] * (2 * max_n + 1)

    for i in range(2, 2 * max_n + 1):
        fact[i] = fact[i - 1] * i % mod

    inv_fact[2 * max_n] = modinv(fact[2 * max_n], mod)

    for i in range(2 * max_n - 1, 0, -1):
        inv_fact[i] = inv_fact[i + 1] * (i + 1) % mod

    return fact, inv_fact

def count_valid_permutations(n, fact, inv_fact, mod):
    return fact[2 * n] * inv_fact[n] % mod * inv_fact[n] % mod

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    queries = [int(data[i]) for i in range(1, t + 1)]

    max_n = max(queries)

    fact, inv_fact = precompute_factorials_and_inverses(max_n, MOD)

    results = []
    for n in queries:
        result = count_valid_permutations(n, fact, inv_fact, MOD)
        results.append(result)

    for res in results:
        print(res)

if __name__ == "__main__":
    main()

