def is_composite(x):
    if x <= 1:
        return False
    for i in range(2, int(x**0.5) + 1):
        if x % i == 0:
            return True
    return False

def solve(test_cases):
    results = []
    for n, array in test_cases:
        total_sum = sum(array)
        if is_composite(total_sum):
            results.append((n, list(range(1, n + 1))))
        else:
            # Find an element to remove to make the sum composite
            for i in range(n):
                if is_composite(total_sum - array[i]):
                    indices = [j + 1 for j in range(n) if j != i]
                    results.append((n - 1, indices))
                    break
    return results

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    index = 0
    t = int(data[index])
    index += 1
    test_cases = []

    for _ in range(t):
        n = int(data[index])
        index += 1
        array = list(map(int, data[index:index + n]))
        index += n
        test_cases.append((n, array))

    results = solve(test_cases)

    for size, indices in results:
        print(size)
        print(" ".join(map(str, indices)))

if __name__ == "__main__":
    main()

