        index += 1

        # Count the frequency of each character in S
        freq = {}
        for char in S:
            if char in freq:
                freq[char] += 1
            else:
                freq[char] = 1

        # Create the lexicographically smallest permutation of S
        sorted_chars = sorted(S)

        # Check if T is a subsequence of the sorted S
        def is_subsequence(s, t):
            it = iter(s)
            return all(c in it for c in t)

        # If T is not a subsequence, we are done
