def is_consistent(s):
    n = len(s)
    if n == 1:
        return True
    # Check for consistency in the string
    for i in range(n):
        if s[i] == 'E' and s[(i + 1) % n] == 'N':
            return False
        if s[i] == 'N' and s[(i + 1) % n] == 'E':
            return False
    return True

